1. An `OrderItem` class with public get/set properties: string ProductName, int Quantity, decimal UnitPrice
2. An `Order` class with public get/set properties: int Id, string CustomerName, List<OrderItem> Items, decimal Total, DateTime CreatedAt
3. A `CreateOrderRequest` class with public get/set properties: string CustomerName, List<OrderItem> Items
4. A `ValidationError` class with a public get/set property: string Message
5. An `IOrderRepository` interface with methods:
   - void Save(Order order)
   - Order? GetById(int id)
6. An `OrderService` class that:
   - Takes `IOrderRepository` as a constructor parameter
   - Has a method: `OneOf<Order, ValidationError> CreateOrder(CreateOrderRequest request)` that:
     - Returns a ValidationError with message "Customer name is required" if CustomerName is null or empty
     - Returns a ValidationError with message "At least one item is required" if Items is null or empty
     - Otherwise creates an Order, calculates Total as sum of (Quantity * UnitPrice) for each item, sets CreatedAt to DateTime.UtcNow, calls repository.Save(order), and returns the Order

IMPORTANT constraints:
- Include `using OneOf;` at the top of the file.
- Do NOT add any other using statements. The project already has global usings for Xunit, AwesomeAssertions, and NSubstitute.
- Do NOT wrap code in a namespace.
- Do NOT use EF Core or any database context. Use the IOrderRepository interface for persistence.
- OrderItem and Order must be classes (not records) with public get/set properties so they can be instantiated with object initializer syntax.
- CreateOrderRequest must be a class (not a record) with public get/set properties.

Return only valid C# code in a single file.

using OneOf;

public class OrderItem
{
    public string ProductName { get; set; } = string.Empty;
    public int Quantity { get; set; }
    public decimal UnitPrice { get; set; }
}

public class Order
{
    public int Id { get; set; }
    public string CustomerName { get; set; } = string.Empty;
    public List<OrderItem> Items { get; set; } = new();
    public decimal Total { get; set; }
    public DateTime CreatedAt { get; set; }
}

public class CreateOrderRequest
{
    public string CustomerName { get; set; } = string.Empty;
    public List<OrderItem> Items { get; set; } = new();
}

public class ValidationError
{
    public string Message { get; set; } = string.Empty;
}

public interface IOrderRepository
{
    void Save(Order order);
    Order? GetById(int id);
}

public class OrderService
{
    private readonly IOrderRepository _repository;

    public OrderService(IOrderRepository repository)
    {
        _repository = repository;
    }

    public OneOf<Order, ValidationError> CreateOrder(CreateOrderRequest request)
    {
        if (string.IsNullOrEmpty(request.CustomerName))
        {
            return new ValidationError { Message = "Customer name is required" };
        }

        if (request.Items == null || request.Items.Count == 0)
        {
            return new ValidationError { Message = "At least one item is required" };
        }

        var order = new Order
        {
            CustomerName = request.CustomerName,
            Items = request.Items,
            CreatedAt = DateTime.UtcNow,
            Total = request.Items.Sum(item => item.Quantity * item.UnitPrice)
        };

        _repository.Save(order);

        return order;
    }
}

